code = """import json
import re

# Load all business data
businesses = locals()['var_functions.query_db:42']

# Load all review data
reviews_file = locals()['var_functions.query_db:14']
with open(reviews_file, 'r') as f:
    reviews = json.load(f)

print(f'Total businesses: {len(businesses)}')
print(f'Total reviews: {len(reviews)}')

# Extract states from business descriptions
business_to_state = {}
for biz in businesses:
    biz_id = biz['business_id']
    desc = biz['description']
    # Look for state abbreviation pattern
    match = re.search(r',\s*([A-Z]{2})', desc)
    if match:
        business_to_state[biz_id] = match.group(1)

print(f'Businesses with state info: {len(business_to_state)}')

# Map reviews to states
state_reviews = {}
unmapped_reviews = 0
for review in reviews:
    biz_ref = review['business_ref']
    # Convert businessref_X to businessid_X
    biz_id = 'businessid_' + biz_ref.replace('businessref_', '')
    
    if biz_id in business_to_state:
        state = business_to_state[biz_id]
        rating = int(review['rating'])
        if state not in state_reviews:
            state_reviews[state] = []
        state_reviews[state].append(rating)
    else:
        unmapped_reviews += 1

print(f'Reviews mapped to states: {sum(len(ratings) for ratings in state_reviews.values())}')
print(f'Unmapped reviews: {unmapped_reviews}')
print(f'States with reviews: {len(state_reviews)}')

# Calculate statistics for each state
state_stats = []
for state, ratings in state_reviews.items():
    state_stats.append({
        'state': state,
        'review_count': len(ratings),
        'avg_rating': round(sum(ratings) / len(ratings), 2)
    })

# Sort by review count descending
state_stats.sort(key=lambda x: x['review_count'], reverse=True)

print('\nAll states sorted by review count:')
for stat in state_stats:
    print(f"{stat['state']}: {stat['review_count']} reviews, avg rating {stat['avg_rating']}")

# Get the top state
top_state = state_stats[0]

print(f'\nTop state: {top_state["state"]}')
print(f'Review count: {top_state["review_count"]}')
print(f'Average rating: {top_state["avg_rating"]}')

print('__RESULT__:')
print(json.dumps(top_state))"""

